¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€¦Ã‚Â¡ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â±.');
    _mobileTelemetry.track(
      eventName: MobileEventNames.tripStart,
      category: 'trip',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': 'success',
        'routeId': routeContext.routeId,
        'tripId': tripId,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.startTripCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: const <String, Object?>{
        'result': 'success',
      },
    );
    context.go(
      _buildDriverHomeRoute(
        previewRouteId: routeContext.routeId,
        startedRouteId: routeContext.routeId,
        forceRefresh: true,
      ),
    );
  } on FirebaseFunctionsException catch (error) {
    if (!context.mounted) {
      return;
    }
    final message =
        _resolveStartDriverTripFailureFeedbackMessageUseCase.execute(
      errorCode: error.code,
      errorMessage: error.message,
    );
    _mobileTelemetry.track(
      eventName: MobileEventNames.tripStart,
      category: 'trip',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': 'error',
        'code': error.code,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.startTripCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: <String, Object?>{
        'result': 'error',
        'code': error.code,
      },
    );
    _showInfo(context, message);
  }
}

Future<bool> _showStartTripUndoWindow(
  BuildContext context, {
  required String routeName,
}) async {
  Timer? countdownTimer;
  var remainingSeconds = 10;
  var timerStarted = false;
  try {
    final result = await showDialog<bool>(
      context: context,
      barrierDismissible: false,
      builder: (dialogContext) {
        return StatefulBuilder(
          builder: (dialogContext, setDialogState) {
            if (!timerStarted) {
              timerStarted = true;
              countdownTimer =
                  Timer.periodic(const Duration(seconds: 1), (timer) {
                if (!dialogContext.mounted) {
                  timer.cancel();
                  return;
                }
                remainingSeconds -= 1;
                if (remainingSeconds <= 0) {
                  timer.cancel();
                  Navigator.of(dialogContext).pop(true);
                  return;
                }
                setDialogState(() {});
              });
            }
            final progress = (10 - remainingSeconds) / 10;
            return AlertDialog(
              title: const Text('Sefer Baslatiliyor'),
              content: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: <Widget>[
                  Text(routeName),
                  const SizedBox(height: 12),
                  Text(
                    'Sefer $remainingSeconds sn sonra baslayacak.',
                    style: const TextStyle(fontWeight: FontWeight.w700),
                  ),
